/**
 * Shared document event delegation.
 *
 * Instead of N tooltips each calling document.addEventListener(type, handler),
 * we maintain ONE document listener per event type and phase. When the event
 * fires, we iterate through all registered handlers for that type.
 *
 * This reduces document-level listeners from O(N × eventTypes) to O(eventTypes).
 */

type Handler = (event: Event) => void

type HandlerSets = {
  bubble: Set<Handler>
  capture: Set<Handler>
}

const handlersByType = new Map<string, HandlerSets>()

function getOrCreateSet(eventType: string, capture: boolean): Set<Handler> {
